parameters.jsonBody:
={{ JSON.stringify({
  type: 'VSphereBackup',
  name: $('Execute Workflow Trigger').item.json.jobName,
  description: $('Execute Workflow Trigger').item.json.jobDescription || 'Created by BackupPaw',
  isHighPriority: false,
  virtualMachines: {
    includes: [{
      platform: 'VSphere',
      type: 'VirtualMachine',
      hostName: $('Execute Workflow Trigger').item.json.hostName,
      name: $('Execute Workflow Trigger').item.json.vmName,
      objectId: $('Execute Workflow Trigger').item.json.objectId
    }],
    excludes: { vms: [], disks: [] }
  },
  storage: {
    backupRepositoryId: $('Execute Workflow Trigger').item.json.repositoryId,
    backupProxies: { autoSelectEnabled: true, proxyIds: [] },
    retentionPolicy: {
      type: 'RestorePoints',
      quantity: parseInt($('Execute Workflow Trigger').item.json.retentionPoints) || 7
    },
    advancedSettings: {
      backupModeType: 'Incremental',
      synthenticFulls: { isEnabled: true, days: ['saturday'] }
    }
  },
  schedule: {
    isEnabled: true,
    daily: {
      dailyKind: 'Everyday',
      isEnabled: true,
      localTime: $('Execute Workflow Trigger').item.json.scheduleTime || '22:00'
    },
    retry: { isEnabled: true, retryCount: 3, awaitMinutes: 10 }
  }
}) }}
